fixes.replacement:
static void cleanup(Node *n)
{
    if (n)
    {
        for (int i = 0; i < 4; i++)
        {
            if (cache[i] == n)
                cache[i] = NULL;
        }
        if (n->data)
            free(n->data);
        free(n);
    }
}
